ll query(int x, int k) {
	// 要求 x ^ y >= k
	// pre = x ^ y，要求前缀 01 pre 本身就已经 > k
	// 算 pre 出现的次数

	int now = root;
	ll res = 0;
	fb(i, MAX, 0) {
		int bit = 1 << i;
		if (k & bit) {
			if (x & bit)now = tr[now].children[0];
			else now = tr[now].children[1];
		}
		else {
			int tmp;
			if (x & bit)tmp = tr[now].children[0], now = tr[now].children[1];
			else tmp = tr[now].children[1], now = tr[now].children[0];
			if (tmp)res += tr[tmp].cnt;
		}
		if (!now)return res;
	}
	return res + tr[now].cnt;
}

